INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027c04e3c98b09417659f8', '非常舒适的一次住宿！感谢前台zara小姐姐，给我们安排了一个舒适的房间，全程接待效率快安排好。酒店风景好漂亮，下次还会来', '["https://dimg04.c-ctrip.com/images/0234v12000gjtsub166D4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233m12000gjvxt0cB585_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000gjw2uze90CE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-07', '红棉大床套房', '套房', '家庭亲子', 60, 0, 3, 6, '["整体满意度","前台服务","景观/朝向"]'::jsonb, '整体满意度', '前台服务', '景观/朝向'),
('68027c04e3c98b09417659f9', '服务不错，酒店环境不错，各色绣球花不错', '["https://dimg04.c-ctrip.com/images/0232c12000etshwn2CCDA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-19', '花园双床房', '双床房', '家庭亲子', 19, 0, 10, 4, '["整体满意度","前台服务","客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务'),
('68027c04e3c98b09417659fa', '周末带小朋友到广州玩，无意中订到的花园酒店原来是一家宝藏酒店，比我的年龄还大，但各方面一点都不落后，设施绝对一流，服务十分到位，不愧为白金五星。
酒店周边配套很成熟，出行也很方便，出门就是地铁口，到市内多个景区也就半小时车程，周末过来citywalk感觉挺好的。退房后前台可以寄存行李，下午可以继续逛吃。
总之是一次满意的入住体验。', '["https://dimg04.c-ctrip.com/images/0232c12000dc4u4ua3FC4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236i12000dc4rcz222D2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000dc4p6885F4A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000dc4s5hu24BE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232612000dc4uz5vAEA6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000dc4ljegC633_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-03', '花园双床房', '双床房', '家庭亲子', 166, 0, 5, 8, '["整体满意度","周边配套","交通便利性"]'::jsonb, '整体满意度', '周边配套', '交通便利性'),
('68027c04e3c98b09417659fb', '真是宝藏酒店啊，本身就是个度假地，很气派精致优雅老钱风，有历史有文化有品位，瀑布餐厅，岭南花园，各种餐厅，小黄鸭是超大套房，还有一座宝藏的博物馆。服务水平高，总之就是让客人觉得舒适又体面。', '["https://dimg04.c-ctrip.com/images/0236412000d8pjfnqC231_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000d8pb3pn32B9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000d8pdopmC1D5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000d8pkbvpE206_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000d8p96peA1A4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236m12000d8pa0tt1DAB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234s12000d8p93et78AA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236t12000d8pky90D9D1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000d8pczq70AF2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-19', '盼酷小黄鸭亲子主题大床房', '主题房', '家庭亲子', 94, 0, 10, 8, '["整体满意度","公共设施","餐饮设施"]'::jsonb, '整体满意度', '公共设施', '餐饮设施'),
('68027c04e3c98b09417659fc', '酒店从设施，装修风格及配置都非常高品质。服务员也很敬业，Gillian 给了我宾至如归的感觉。', '["https://dimg04.c-ctrip.com/images/0231x12000e3ij7aq381B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-21', '花园大床房', '大床房', '独自旅行', 47, 0, 6, 7, '["房间设施","前台服务","整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度'),
('68027c04e3c98b09417659fd', '酒店大堂豪华大气，迎宾员热情周到，房间整洁、干净、卫生，配套设施齐全，服务态度很好，酒店赠送的欢迎点心很漂亮，口感也很好，很满意。', '["https://dimg04.c-ctrip.com/images/0232k12000dqrgt4gB09F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000dqqway17857_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000dqr77bjEEBC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231312000dqr3yzlAA86_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-21', '花园双床房', '双床房', '商务出差', 65, 0, 22, 7, '["整体满意度","卫生状况","前台服务"]'::jsonb, '整体满意度', '卫生状况', '前台服务'),
('68027c0ee3c98b09417659fe', '房间装修很好，整洁，空气清新。
酒店大堂豪华大气，很多旅客在大堂拍照留念，我们也不例外。
酒店门口有循环车道，方便接送客户。还设有临时停车场，充电桩，规划得很周到。
花园酒店的五星级实至名归，快来体验吧！', '["https://dimg04.c-ctrip.com/images/0230j12000dbytjd47062_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234t12000dbyutin3A83_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-03', '花园大床房', '大床房', '商务出差', 102, 0, 15, 8, '["房间设施","公共设施","整体满意度"]'::jsonb, '房间设施', '公共设施', '整体满意度'),
('68027c0ee3c98b09417659ff', '环境优美，服务热情，卫生干净，房间设施还行。', '["https://dimg04.c-ctrip.com/images/0236e12000eqb02d07362_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000eqbbfz19DC9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235d12000eqb4sws0DA6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-09', '花园双床房', '双床房', '家庭亲子', 22, 0, 14, 5, '["整体满意度","卫生状况","房间设施"]'::jsonb, '整体满意度', '卫生状况', '房间设施'),
('68027c0ee3c98b0941765a00', '后花园完美诠释花园酒店这个名称，还有酒店处处都有艺术插花和兰花盆栽装饰，很吸我这个鲜花控。
健身室器材很多，保养得也不错，不逊正规健身房了。桑拿房干湿都有，唯一的缺点是没有冰毛巾。露天游泳池挺大，遗憾的是冬天没有开放。
行政走廊服务不错，但是空间比较小，餐食比较少，跟文华比差得不是一星半点。下午茶时间有红酒，可以小酌红酒一杯。欢乐时间的餐点都是冷盘，建议可以增加一两款热汤食，例如云吞面或者牛腩粉这种有广州特色的粉面，即能让外宾尝试广州美食也能满足中国胃。
入住的是基本房间，空间比较小也能理解，没有浴缸。
生日有小布置，还送了好吃的山楂蛋糕，加分。
有个酒店博物馆可以参观，可以了解一下酒店发展史，不错。
老牌五星酒店，外宾比较多。', '["https://dimg04.c-ctrip.com/images/0233c12000d2btjcb34A3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235w12000d2bstwa2A82_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q12000d2bowki3948_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235w12000d2bi3brED90_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000d2bu7gmD383_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232k12000d2bnzrbA60E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000d2bh4qw3F78_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000d2bhkbjB8DA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233312000d2bjfeg338F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-28', '花园双床房', '双床房', '家庭亲子', 318, 0, 5, 9, '["公共设施","餐饮设施","整体满意度"]'::jsonb, '公共设施', '餐饮设施', '整体满意度'),
('68027c0ee3c98b0941765a01', '不错，酒店干净，服务也挺好，停车免费。下次出玩还选这家。', '["https://dimg04.c-ctrip.com/images/0234p12000elmw6sh899A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000elmxxg760C2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-28', '花园双床房', '双床房', '家庭亲子', 28, 0, 7, 5, '["卫生状况","前台服务","公共设施"]'::jsonb, '卫生状况', '前台服务', '公共设施'),
('68027c0ee3c98b0941765a02', '设施：房间里面偏旧，员工衣服太老土了，还不合身，皱皱巴巴
卫生：一般，但是送了一份欢迎水果，不过不打招呼就私自放进房间有点吓人
环境：后面小花园蛮美的，但是不住也能去看，大厅也不错，就是感觉很乱
服务：还可以，主动帮忙拍照
总体而言，老式酒店，进去看看就行，特意住是真没必要', '["https://dimg04.c-ctrip.com/images/0232r12000dal3tpu776D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231912000dal6zg6DE0B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g12000dalism10421_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-02-26', '花园双床房', '双床房', '家庭亲子', 137, 0, 16, 7, '["房间设施","整体满意度","卫生状况"]'::jsonb, '房间设施', '整体满意度', '卫生状况'),
('68027c0ee3c98b0941765a03', '我们一家人选择在2024年的除夕之际，共赴广州花园酒店，开启了一段难忘的四天三夜之旅。酒店的环境、服务以及餐饮都让我们深感满意，让我们在南方的春节中，尽享了浓厚的年味。
广州花园酒店为我们提供了舒适的住宿环境，无论是房间的清洁度还是设施的完备性，都让我们倍感满意。在餐饮方面，酒店的年夜饭更是让人回味无穷，每一道菜品都充满了南方独特的年味，让我们一家人在除夕夜品尝到了家的味道。同时，酒店的卫生和服务也是无可挑剔的，让人感受到了一份温馨和关怀。
此次广州之旅，让我们充分领略了南方春节的独特魅力。酒店为我们呈现了一场别开生面的年味盛宴，让我们一家人在欢乐和温馨中度过了一个难忘的除夕之夜。
广州花园酒店无疑是一家高品质的酒店，无论是从硬件设施还是从服务细节上，都展现了其专业和贴心的水准。我们在此次旅行中收获了满满的愉快体验，我们愿意向更多的朋友推荐广州花园酒店，也期待未来再次来到这里。', '["https://dimg04.c-ctrip.com/images/0200x12000d6rynjnC3CE_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0232f12000d6rpim0170D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230z12000d6rtu207DEA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233812000d6rvhf20080_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230h12000d6rmz7n79B2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000d6rm1fg6F2D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000d6rwcwm1BC8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000d6rhk91B994_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000d6rwsud7F52_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233412000d6rbda38B5E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-12', '粤韵双床套房', '套房', '家庭亲子', 394, 0, 5, 8, '["整体满意度","餐饮设施","房间设施"]'::jsonb, '整体满意度', '餐饮设施', '房间设施'),
('68027c0ee3c98b0941765a04', '第三次来广州，果断选择花园酒店，免费升级了房间，非常感谢，前台服务态度也很好，非常满意的入住体验，下次来还会选择花园酒店', '["https://dimg04.c-ctrip.com/images/0232312000dqu63vn5EF6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000dqu8c2uC194_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234f12000dquc2i24C7C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2024-04-22', '花园大床房', '大床房', '家庭亲子', 60, 0, 3, 6, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027c0ee3c98b0941765a05', '卫生：不错
环境：不错
服务：不错
都不错就是房间稍微小了一点而已', '["https://dimg04.c-ctrip.com/images/0232812000eduib0r1EBF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000educvvrE788_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000educ1fk1874_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231g12000edu98c2F388_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-06-08', '城央绿意双床房', '双床房', '商务出差', 33, 0, 14, 4, '["房间设施","整体满意度","卫生状况"]'::jsonb, '房间设施', '整体满意度', '卫生状况'),
('68027c0ee3c98b0941765a06', '地理位置很好 出门就是地铁', '["https://dimg04.c-ctrip.com/images/0233112000fox84nnB267_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-22', '花园双床房', '双床房', '家庭亲子', 13, 0, 5, 4, '["交通便利性"]'::jsonb, '交通便利性', NULL, NULL),
('68027c0ee3c98b0941765a07', '五星级酒店，满意服务', '["https://dimg04.c-ctrip.com/images/0233312000f4vsojv4827_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233412000f4vs3elBD3A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000f4vtygn0142_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-15', '红棉双床套房', '套房', '商务出差', 10, 0, 14, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027c1ae3c98b0941765a08', '酒店位置很便利，离华桥村很近，出门就是地铁口。周边很多当地有名的餐厅，基本你能想到的都有。大厅前台工作人员很多，主动帮拿行李，主动帮叫电梯，还有很多外籍服务人员，很国际化的老牌五星酒店。我这间房早餐是在30层旋转餐厅用餐，360度无死角边赏美景边用餐。ps：早餐炒菜类调整一俩道中式热炒会更好！', '["https://dimg04.c-ctrip.com/images/0234o12000dacfajoF531_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000dacf5pyE05B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000dacghh445A6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-25', '粤韵双床套房', '套房', '家庭亲子', 147, 0, 39, 9, '["交通便利性","周边配套","餐饮设施"]'::jsonb, '交通便利性', '周边配套', '餐饮设施'),
('68027c1ae3c98b0941765a09', '冲着花园酒店去的，酒店花园名副其实，夜景也很漂亮，但酒店内有些陈旧，我们住的这间咖啡机也是坏的，有些失望。走的时候原本想参观酒店博物馆，谁知星期一闭馆，又是遗憾。', '["https://dimg04.c-ctrip.com/images/0236g12000dmzdkvlBAFA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000dmzvduh4CE5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000dmzvjc0A43F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s12000dmzl9euDBFD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236o12000dmzcxz17FBF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230y12000dmzq8sw7CD9_R_150_150_R5_Q70_D.webp","https://dimg04.c-ctrip.com/images/0231u12000dmzu9s1F119_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000dmzpf7e3D58_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000dmzq556EFC7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.8, 3, '2024-04-10', '城央绿意大床房', '大床房', '情侣出游', 81, 1, 15, 7, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('68027c1ae3c98b0941765a0a', '位置交通：位于环市东路淘金站上盖的花园酒店.公交地铁非常便利，酒店里也设有停车场，但私人车位居多。房间景观：有多种客房、套房可供选择：粤韵客房、花园客房、岭南套房等，丰俭由人。餐厅：有9间餐厅可供就餐，中西法日各式菜系，还有酒吧咖啡厅等不同休闲应酬场所，适合各种人士的需求。服务：酒店大堂服务非常认真细致，主动打招呼、帮推门拿行李，外语交流流利。餐厅服务员热气好客，随传随到，斟茶收盘及时。其他：户外有个几层楼高的景观瀑布，在瀑布餐厅就餐可以一览无余：后门出口有网球场：写字楼区1-3楼有日本驻广州总领馆。室内除了餐厅外，还有多家时装服饰和艺术品商铺，3楼有9间多功能会议室和1个国际会议中心，经常举办大型国际性商务会议；4楼还有花园酒店博物馆，扫码实名登记可以进馆参观，馆内收藏有酒店故事和发展变迁的珍贵照片藏品，丰富了花园酒店的内涵。
行政走廊的Kanchan,Cathy,Beryle,前台服务人员kasas,betty温和有礼，热情招待', '["https://dimg04.c-ctrip.com/images/0232r12000f6qbug5F26C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232u12000f6qbt3pAD4D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000f6qa31gA328_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000f6qbyk09726_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231o12000f6qggbs8A71_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000f6q8q23505F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000f6pmp18330A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234j12000f6qdlv47601_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232b12000f6qc6zn96BA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-20', '花园大床房', '大床房', '情侣出游', 422, 0, 1, 10, '["交通便利性","周边配套","前台服务"]'::jsonb, '交通便利性', '周边配套', '前台服务'),
('68027c1ae3c98b0941765a0b', '房间干净，安静，妈妈说枕头特别好睡，出行方便，周围好吃的店很多，宝宝每日的必备项目就是去小花园喂鱼，推荐入住', '["https://dimg04.c-ctrip.com/images/0232p12000du2be8iC0F7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230h12000du27zylE9FB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233j12000du2xvbz59E5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230112000du2iny55522_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-30', '花园大床房', '大床房', '家庭亲子', 54, 0, 7, 7, '["卫生状况","安静程度","周边配套"]'::jsonb, '卫生状况', '安静程度', '周边配套'),
('68027c1ae3c98b0941765a0c', '槽点略多的酒店。
1. 携程上显示金卡可以升级房型，办理入住时表示要视当日房量而定，能理解，但我查看平台发现更高级的房型全都没有售空，希望前台再争取一下。前台女生走到旁边和另一个男生沟通，还没把我的诉求说完那个男生就立马说不行。当拒则拒，非常喜欢这种干脆果断的男生。
2. 房间明显有做翻修，但是翻修后的保养依然不太好。沙发套、办公椅等属于深度保洁的部分应该是没有常做的。浴缸有灰有毛发，日常保洁也欠佳。同时玻璃通透度太好了，不拉窗帘晚上恐有艳照门风险。
3. 外卖柜的位置令人感到匪夷所思。大堂设计本来就欠妥当，各种意义不明的隔断让人眼花缭乱，外卖柜更是设置在大堂深处角落。两个外卖柜不在一起不说，其中一个还设置在店铺里，标示牌也不明确。外卖员从正门进入酒店后要穿过整个大堂越过住客电梯厅才能到达外卖柜，所以大堂里乱哄哄的。这也是我第一次外卖送达取餐柜后被其他住客误取（这一点不完全是酒店责任，但也不能说完全和酒店无关。）
4. 外籍工作人员在入住期间打我手机求好评。相当不能理解，因为是外国人所以中文说得很艰难，考虑到他工作的辛苦我还是努力和他沟通希望听懂他的意思，但最后还是艰难地失败了，因为我听不懂他的名字。希望酒店可以让中外籍工作人员各管各的吧，是不愿意招中国人吗？
5. 花园瀑布挺漂亮的，但是晚上也开得太晚了，窗户隔音不好，明媚晴朗的夜晚听上去外面像在下暴雨。
整体看下来，酒店整体运营应该是遇到了一些问题，品控相当一般。
除去缺点以外，其他各方面表现（床品、个护用品、房间大小、地理位置等）也仅仅是尚可，和做得较好的连锁酒店是差不多的。表现最优秀的是餐饮，但是广州五星级酒店餐饮大多不差，甚至还有很出色的，故而也没有什么竞争力。', '["https://dimg04.c-ctrip.com/images/0230f12000d9ilv7fF4F6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234612000d9itm2v2A42_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230y12000d9j29511515_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232812000d9j1muh8B27_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.5, 2, '2024-02-21', '花园大床房', '大床房', '独自旅行', 722, 16, 13, 9, '["客房服务","安静程度","整体满意度"]'::jsonb, '客房服务', '安静程度', '整体满意度'),
('68027c1ae3c98b0941765a0d', '大堂一进去很是惊艳，金碧辉煌，迎宾小妹的衣服更是金光闪闪，印象深刻。因为是老酒店改造，房间大小适中，不过陈设新颖。这里的服务员好多是外国人，还见到一些国外空乘人员。二楼的荔湾餐厅味道和风格都很独特正宗，连吃了两顿，省却了觅食的舟车劳顿，很加分。外出北京路步行街很方便，去机场也不远。', '["https://dimg04.c-ctrip.com/images/0236s12000d8hj7oq4673_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232612000d8heouzC7E1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-18', '花园双床房', '双床房', '家庭亲子', 141, 0, 13, 8, '["周边配套","餐饮设施","整体满意度"]'::jsonb, '周边配套', '餐饮设施', '整体满意度'),
('68027c1ae3c98b0941765a0e', '服务给的三星：
客房服务很好，特别是2月17日晚上帮2510房间测试Wi-Fi连接的阿姨和技术部门男士，以及18日上午整理房间的小帅哥。
对比去年年前入住的体验，礼宾和前台有明显的疲惫感和生无可恋脸，人手也比去年少。估计是春节客流高峰所致。三星评价由此而来。

酒店位置很好，地铁打车公交都很方便。
设施维护很好。卫生很好。
红棉房据说是23年重新装修过，很新，房间一切都满意，就是2510房经测试没有Wi-Fi信号，希望酒店稍后调整，不再影响后面的住客。
早餐就中规中矩，倒是吃到了久违的烟熏三文鱼。好像疫情三年很多酒店都把这道取消了？（个人理解和经历）', '["https://dimg04.c-ctrip.com/images/0236612000d97swjs3988_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000d97thxwC80F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236112000d97t62v109E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000d97tyi76995_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237212000d97swjuD352_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-02-20', '红棉双床套房', '套房', '家庭亲子', 278, 0, 8, 9, '["客房服务","前台服务","房间设施"]'::jsonb, '客房服务', '前台服务', '房间设施'),
('68027c1ae3c98b0941765a0f', '房间温馨雅致，床垫软熟柔软，睡的很好.行政走廊Lina小姐姐服务很好，很温柔。', '["https://dimg04.c-ctrip.com/images/0236112000e5qnrzzC22C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-25', '花园大床房', '大床房', '商务出差', 39, 0, 8, 6, '["房间设施","前台服务"]'::jsonb, '房间设施', '前台服务', NULL),
('68027c1ae3c98b0941765a10', '酒店帮我们?升级了房型 很喜欢性价比很高', '["https://dimg04.c-ctrip.com/images/0231h12000fout4g55308_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235p12000fouq4nwD9C1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000foug1xb7B40_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-09-22', '红棉双床套房', '套房', '朋友出游', 20, 0, 2, 4, '["性价比","整体满意度"]'::jsonb, '性价比', '整体满意度', NULL),
('68027c1ae3c98b0941765a11', '不愧为广州老牌高星级酒店，大气依旧，虽然智能化不一定跟得上现在的一些现代化未来酒店，但处处体现的人文让宾客感受暖心。尤其是酒店自带博物馆、私家花园，地理位置相当方便，门口就是地铁站，周边环东商区，游购娱吃喝玩乐都很近。隔壁就是一家点都德，对面还有一家广州酒家。总之住花园酒店令本次旅程增色加分不少。', '["https://dimg04.c-ctrip.com/images/0202j12000d8i2lodAF8A_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0230u12000d8hpaqfC1E3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233a12000d8hln3l7442_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000d8i1k4895BF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235612000d8i2k925ADE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233812000d8i1zkx271D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000d8ht1aj55CD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000d8hw1n2A6A6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233q12000d8hs1nsBA6E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234l12000d8hx57d565A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-18', '城央绿意大床房', '大床房', '家庭亲子', 149, 0, 6, 9, '["周边配套","交通便利性","整体满意度"]'::jsonb, '周边配套', '交通便利性', '整体满意度'),
('68027c25e3c98b0941765a12', '老牌酒店还是靠谱的', '["https://dimg04.c-ctrip.com/images/0230612000ewxhzdf0DCE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-27', '花园双床房', '双床房', '家庭亲子', 9, 0, 2, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027c25e3c98b0941765a13', '房间挺大，有套间，室内外设计很好，环境很美，花园尤其美，有两个瀑布，很多锦鲤和花，名副其实的花园酒店，服务还好，酒店博物馆周一闭馆', '["https://dimg04.c-ctrip.com/images/0235b12000dmwfn3q177C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231c12000dmwrtp3D92E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237312000dmwy5ojE9D4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-10', '红棉大床套房', '套房', '家庭亲子', 65, 0, 19, 7, '["房间设施","整体满意度","周边配套"]'::jsonb, '房间设施', '整体满意度', '周边配套'),
('68027c25e3c98b0941765a14', '久负盛名的花园酒店，盛名之下其实难副。一流的环境，二流的设施，三流的餐品。酒店占据广州核心区位，后花园是最大亮点。作为中国为数不多的白金五星，办理入住居然要15分钟，完全缺少宾至如归的感觉，减分；客房比较干净，布局和配置也相对合理、精细，但是设施太老旧，白金五星居然不配智能马桶，减分；早餐种类乏善可陈，口味一般，由于场地局促，高峰时间吃饭等位严重，11点的早餐截止时间，10点30就撤摊，岂是待客之道，减分。
建议亲子度假游客，可选不含早的套餐，避免踩坑。', '["https://dimg04.c-ctrip.com/images/0233r12000d6rnal35FA7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000d6ro08z6D13_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000d6rrualA8A5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000d6rqncm62F0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q12000d6rp5km2EC8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000d6rq2ol861A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000d6rp0x780C3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000d6rp7ngEE3B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000d6rouuvB151_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2024-02-12', '花园大床房', '大床房', '家庭亲子', 229, 1, 9, 9, '["房间设施","餐饮设施","退房/入住效率"]'::jsonb, '房间设施', '餐饮设施', '退房/入住效率'),
('68027c25e3c98b0941765a15', '花园酒店让我有点失望！首先排队入住站着等了半小时多！不知道???什么可说的队伍一直没怎么动！终于排到我了吧居然居然被告知还要两小时才能有房！我的天啊我带两娃这么热的天喊我去哪里等！还说的好听给我安排景色好的高楼层！本来花园房就是21楼啊！你也没升级也没送早餐的！没什么好的体验感！
早餐也没啥特别的！就是瀑布餐厅景色不错！有花有??适合拍照??', '["https://dimg04.c-ctrip.com/images/0236q12000d8jc74kE96B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3, 3, '2024-02-18', '花园双床房', '双床房', '家庭亲子', 172, 2, 22, 8, '["退房/入住效率","前台服务","整体满意度"]'::jsonb, '退房/入住效率', '前台服务', '整体满意度'),
('68027c25e3c98b0941765a16', '设施：设施都很新，尤其是过年入住非常有节日氛围

服务：服务一般，金卡会员不能升级房型。并且可能是因为人多，让我们先去逛再来办理入住，说到时候收拾出来会给我们发短信，等了一个半小时也没有收到短信，最后去了前台说有房可以入住了，属实有点耽误时间
早餐：早餐我们在旋转餐厅吃的，环境很好，吃的也中规中矩', '["https://dimg04.c-ctrip.com/images/0234512000d80norz4D28_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234t12000d80vyr4A9B3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000d80os8tAA25_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000d80rmo0E06B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2024-02-16', '花园大床房', '大床房', '情侣出游', 149, 0, 4, 7, '["退房/入住效率","餐饮设施","整体满意度"]'::jsonb, '退房/入住效率', '餐饮设施', '整体满意度'),
('68027c25e3c98b0941765a17', '之前几年每次来广州出差都住花园，开会睡觉两点一线倒也没留下什么印象，这一次携老小来广州过年；顺手订了熟悉的花园，没想到意外惊喜，成为此行最满意的一个决定：花园酒店竟然有个大！花！园！来了这么多次都没注意过，瀑布小桥流水锦鲤，草坪鲜花，妥妥一个精致的城市园林，还不用人挤人，两娃每天都去花园里玩耍放电；来的当天是初五，大堂摆着年味集市，工作人员发金币巧克力和糖果，高跷财神合影，充满了浓浓的年味；服务也是120分，每层的电梯间都站了一位员工，迎来送往问好祝贺，亲切有礼举止专业；最最过意不去是小朋友突发肠胃炎，弄脏了床单，凌晨四点一个电话立刻来换被子和床褥，全程安慰也没有收清洁费；第二天半夜又弄脏了…依旧火速赶到换床品，住了两晚基本都在照顾小朋友生病中度过，是花园员工的温暖让我们的熬夜照料变得不那么痛苦，真的非常感动～以后来广州一定认准花园！', '["https://dimg04.c-ctrip.com/images/0232312000d8bivk1D947_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234612000d8bh4a01407_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231f12000d8bgpu9F9C2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-17', '花园大床房', '大床房', '家庭亲子', 372, 1, 10, 10, '["客房服务","整体满意度","公共设施"]'::jsonb, '客房服务', '整体满意度', '公共设施'),
('68027c25e3c98b0941765a18', '非常nice 的酒店，还会再光临。', '["https://dimg04.c-ctrip.com/images/0232g12000eosx9lw8C5C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-05', '红棉双床套房', '套房', '其他', 17, 0, 4, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027c25e3c98b0941765a19', '按照约定2点check in时说没有空房要等待，没有任何主动的补偿措施。和前台说不要尾房，结果还是给开了一间尾房，重新排队一个小时等待换房间。房间隔音很差，旁边房间的小孩吵闹都能听到，投诉多次无果，下次不会再考虑花园酒店。', '["https://dimg04.c-ctrip.com/images/0230y12000dacj0eyFF07_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231412000dacj56z0B4A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231712000dacik2t2226_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.5, 1, '2024-02-25', '城央绿意大床房', '大床房', '其他', 111, 5, 7, 8, '["退房/入住效率","前台服务","安静程度"]'::jsonb, '退房/入住效率', '前台服务', '安静程度'),
('68027c25e3c98b0941765a1a', '热闹非凡的大堂，春节活动很多，人也很多，但丝毫没感觉到乱，反而很有氛围，电梯门厅和客房楼层电梯口都有迎宾接待服务，还热情地帮我们订楼下米其林餐厅的位子，从大门口开车门的服务员开始就一路给人如沐春风的感觉。
酒店地理位置很好，本身有一个小花园，有瀑布景观，对面是友谊商店，里面有广州酒家，酒店边上是点都德，去景区打车也都20分钟左右就可以。
尤其赞的是酒店里面就有三家米其林，不出酒店就可以吃到地道地美食。', '["https://dimg04.c-ctrip.com/images/0234b12000d7oly1mC307_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234n12000d7oliahB59F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000d7okpud4004_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236z12000d7oly1sBE87_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-15', '红棉大床套房', '套房', '其他', 202, 0, 12, 9, '["前台服务","周边配套","餐饮设施"]'::jsonb, '前台服务', '周边配套', '餐饮设施'),
('68027c25e3c98b0941765a1b', '说真心话没想到过年期间酒店这么火爆，但还是要为酒店点赞??，一流的服务，房间虽小，但设施齐全，床垫不错??酒店的服务态度都很好??。酒店的经典设计风格很独特，最关键的是出行方便，地铁就在旁边。来广州玩了两天，便捷的交通，舒适的入住体验还是不错滴', '["https://dimg04.c-ctrip.com/images/0230b12000d89z21oB67E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230m12000d89yyujD0CF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236j12000d89yw406D2A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-17', '花园双床房', '双床房', '朋友出游', 122, 0, 17, 7, '["交通便利性","整体满意度","房间设施"]'::jsonb, '交通便利性', '整体满意度', '房间设施'),
('68027c34e3c98b0941765a1c', '宾至如归，花园漂亮！老牌服务，大气！整个酒店虽然有一些年头了，但都做了整体的装饰新老结合中西合璧，颇有岭南地区的艺术美感。瀑布餐厅也是一大特色，孩子们还可以去花园喂鱼。如果有机会还会再次入住。', '["https://dimg04.c-ctrip.com/images/0232m12000d94x8y2716E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235712000d94znguE6E9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232z12000d95ae71A1F0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000d952pmm98E0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000d95cr3vF30F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000d952eq655EC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-20', '花园双床房', '双床房', '家庭亲子', 96, 0, 29, 8, '["整体满意度","公共设施","餐饮设施"]'::jsonb, '整体满意度', '公共设施', '餐饮设施'),
('68027c34e3c98b0941765a1d', '酒店位于老城区，老牌酒店，服务不错！过年气氛好，酒店里面饭店也多，各种价位都有！选了桃园高端粤菜！菜品没话说，就是价格真的好贵！唯一不足，酒店卫生间设施老旧了点，淋浴房是浴缸，爬进爬出的，而且卫生间是敞开式！不太方便！隐私不够！', '["https://dimg04.c-ctrip.com/images/0234q12000d7x7ry44B47_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000d7x9yty8FAB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230k12000d7xcbhxFA16_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000d7xjq39EED6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-16', '花园双床房', '双床房', '家庭亲子', 114, 0, 8, 8, '["房间设施","餐饮设施","价格合理性"]'::jsonb, '房间设施', '餐饮设施', '价格合理性'),
('68027c34e3c98b0941765a1e', '好不容易出差这次可以住上了。之前来因为到别的区去一直没住上。酒店大堂香味怡人，服务人员主动帮忙，热心。环境优雅，设施高级，卫生一直都很好。非常推荐', '["https://dimg04.c-ctrip.com/images/0235x12000dibtxtg9F31_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000dibv7k9112D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000dibvcmv9B84_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000dibbainA15F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230z12000dibghl97048_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-26', '花园大床房', '大床房', '商务出差', 73, 0, 41, 7, '["整体满意度","前台服务","卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况'),
('68027c34e3c98b0941765a1f', '这个酒店超棒！首先 ，出了地铁口就到，对老人家来说很友好。酒店大堂的所有工作人员都态度非常非常亲切面带微笑。办理入住很顺利，看我们小孩是初中生，主动提出免费升了套房加了单人床，让我们在广州的3晚睡了舒服级了，并赠送了三套宝格丽的洗护用品套装！度过了美好的假期??', '["https://dimg04.c-ctrip.com/images/0235z12000d72nam31696_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f12000d72pvdy6B67_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233n12000d72n2n82114_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231912000d72dec44DFD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000d72g5qmA1E2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000d722szfB70F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000d726abp72D5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000d72o31s902B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000d72q82qBB82_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-13', '城央绿意双床房', '双床房', '家庭亲子', 131, 0, 9, 9, '["前台服务","交通便利性","整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度'),
('68027c34e3c98b0941765a20', '非常喜欢！酒店有后花园，池子里有很多鱼，小朋友专门买了面包来喂鱼（鱼好肥），有漂亮的瀑布，还有一个博物馆。我们一家四口，原本订的是双床房，前台小哥哥给免费升级成了粤韵大床房，然后加了一个床，房间很大，浴缸泡澡也很舒服，服务非常好也很贴心，总之就是超赞的一次入住体验！', '["https://dimg04.c-ctrip.com/images/0231912000d8sm2odB556_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000d8shgdm4EEE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231612000d8skrhhEBD0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000d8saneiC3A3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236z12000d8slpor60A4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233h12000d8si5au4BD9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-19', '花园双床房', '双床房', '家庭亲子', 133, 0, 6, 9, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68027c34e3c98b0941765a21', '订的红棉房套餐，包早餐和5百餐饮券，应该是重新装修了，红棉房应该对应现在粤韵吧，给的几间都是粤韵；房间很大，设施新，卫生、服务、环境都很好，早餐在瀑布餐厅也不错，4楼还有个博物馆，入住外国人多。餐饮券能在酒吧用。套餐超值。', '["https://dimg04.c-ctrip.com/images/0235m12000d2ds5r3A046_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233112000d2drvo74719_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233712000d2dv38n3F6D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000d2dsnn941A3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f12000d2dtl3qE8F6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236712000d2e12tdA3C3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000d2e1t867CBC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d12000d2dqc7sA4F3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231s12000d2e12tj4D69_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-28', '红棉大床套房', '套房', '家庭亲子', 111, 1, 36, 8, '["性价比","房间设施","餐饮设施"]'::jsonb, '性价比', '房间设施', '餐饮设施'),
('68027c34e3c98b0941765a22', '闹市中的公园酒店，虽然有些老旧，但是维护的很好，服务也好，过年期间酒店大堂布置的霸气奢华，活动也丰富，但是第一次来广州，光忙着在外面玩了，只最后一天吃完早餐才在酒店转了转，玩的太少，下次还会选择', '["https://dimg04.c-ctrip.com/images/0236u12000dzc9zfo2BA7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000dzcbu57B071_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000dzcacx1FB70_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-13', '红棉大床套房', '套房', '家庭亲子', 97, 0, 9, 7, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68027c34e3c98b0941765a23', '酒店自带花园相当不错，瀑布流水锦鲤，非常适合小孩和老人。地理位置也很好。虽然是春节但服务人员很充足并且态度都很好走到哪里都主动打招呼。房间电视有很多海外频道。缺点是房间硬件落后了。插座少特别是床头充电很不方便。空调温度打不上去有点冷，关了反而好点。另外床太软腰不好慎选。', '["https://dimg04.c-ctrip.com/images/0233m12000d6t4otrDBB1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236r12000d6t6gkd0492_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234f12000d6sapu41DBB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233112000d6t2kl59E0F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-02-12', '红棉大床套房', '套房', '家庭亲子', 135, 0, 3, 9, '["房间设施","整体满意度","前台服务"]'::jsonb, '房间设施', '整体满意度', '前台服务'),
('68027c34e3c98b0941765a24', '新年气氛杠杠的，一进门被大堂喜庆的装饰惊艳到了。房间整洁舒适，好评！酒店考虑到春节入住人较多，开了两个自助早餐的餐厅分流客人，很是贴心。每个工作人员都是微笑的跟你说新年好，很是温馨！来广州住花园，没选错！', '["https://dimg04.c-ctrip.com/images/0230512000d6pyj4374E0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000d6pyexh80C5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-12', '城央绿意双床房', '双床房', '家庭亲子', 102, 0, 1, 9, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68027c34e3c98b0941765a25', '酒店非常漂亮，布置充满了年味，年三十入住给人的第一感觉非常好。年初一上午酒店有舞狮活动，第一次近距离接触，非常棒。酒店每个工作人员热情，礼貌，主动打招呼，不愧是老牌五星级酒店。在酒店内有不少可以打卡的地方，有着浓厚的文化氛围！', '["https://dimg04.c-ctrip.com/images/0202512000d73hi5oC08B_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0234v12000d73gu4wD24A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234g12000d72r82vBF9C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-13', '红棉大床套房', '套房', '情侣出游', 113, 0, 31, 8, '["整体满意度","前台服务","公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施'),
('68027c40e3c98b0941765a26', '过年期间酒店住客多，入住排了长队，是我去过的所有酒店里办理入住时间最长的一家。我定的红棉大床房，下午3点办理入住时前台小哥说需要等一个多小时，可以帮我调剂到旁边楼的公寓房，有两个房间，当时我答应了。结果进去一感受，房间非常的旧，90年代装修那种感觉，旁边是长租的那种住客，环境像住居民楼，我受不了要求换到我原订的房间，告诉我还得等打扫完，于是除夕夜等到晚上快10点，终于入住了自己原先定的房间，房间装修比较新，空间也挺大的，就是没房调剂这点操作太让人迷惑了，人家总是往高了调吧，哪有他们这种往差了给我调的，幸亏坚持换回来了，不然真的得难受过年了。酒店服务员态度都挺好的，后花园的环境也很好，早餐种类也还可以，过年的氛围布置都挺用心的。', '["https://dimg04.c-ctrip.com/images/0232b12000d6wrlhr003E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234n12000d6wrx7d7D05_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234u12000d6ws5uq8CF8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-13', '红棉大床套房', '套房', '家庭亲子', 317, 0, 2, 9, '["退房/入住效率","前台服务","整体满意度"]'::jsonb, '退房/入住效率', '前台服务', '整体满意度'),
('68027c40e3c98b0941765a27', '带家人过年，谢谢办理入住的工作人员帮我免费升级了套房，不愧是花园酒店，套房体验好，工作人员热情负责，年味浓。晚上订了团年宴，因为坐在喇叭附近音响太大，跟服务员说了后，很快音量调小了，谢谢那位小姐姐负责有效率。团年宴菜量有些多，后面还有几道菜没上我们就饱了，提前走了。早餐丰盛环境好。', '["https://dimg04.c-ctrip.com/images/0231r12000d66eckq46E3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230c12000d66nloo54B7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000d66nc5l55B4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232312000d66hp7cC4BB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233x12000d669vagC2C6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233h12000d65xdfp9B46_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-10', '红棉双床套房', '套房', '其他', 141, 0, 29, 8, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('68027c40e3c98b0941765a28', '总体品质服务不错，房间设施比较老但是保养还可以，公区旋转餐厅、后花园能看出上世纪最高端5星级酒店的风格，也是个独特的体验。大年三十酒店有很多特色活动非常有氛围，还赠送了几只康乃馨。这个酒店感觉外国客人挺多，还有外籍工作人员。建议：房间增加空气清新或香氛。', '["https://dimg04.c-ctrip.com/images/0236c12000d7q64wk20CD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233n12000d7q8fijDE33_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236312000d7pv9gb5BA6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2024-02-15', '花园大床房', '大床房', '情侣出游', 127, 0, 9, 8, '["房间设施","整体满意度","餐饮设施"]'::jsonb, '房间设施', '整体满意度', '餐饮设施'),
('68027c40e3c98b0941765a29', '春节活动丰富 气氛浓郁 闹中取静的花园有特色
人流特别大 有一天早餐排队太久放弃了 应该预先提醒一下客人的 酒店对满负荷运转的预备不足
房间舒适卫生 客房服务响应及时 地理位置方便
酒店餐厅运营服务水平不敢恭维
和五星级酒店的中餐厅比有较大差距
反映问题后值班经理处理及时 餐厅后续补救措施比较真诚
前台的服务人员无论是中方还是外籍的都热情周到', '["https://dimg04.c-ctrip.com/images/0234f12000d9abo64764A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000d9a9bxqC57F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230c12000d9a49clF5F7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-02-21', '粤韵大床套房', '套房', '家庭亲子', 172, 0, 20, 8, '["餐饮设施","整体满意度","前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务')
 ON CONFLICT (_id) DO NOTHING;
